const StatBar: React.FC<{ label: string; value: number; max: number; color: string; inverse?: boolean }> = ({ label, value, max, color, inverse }) => {
  // Normalize value to percentage
  let pct = (value / max) * 100;
  if (pct > 100) pct = 100;

  return (
    <div className="flex items-center gap-2">
      <div className="w-12 text-slate-400 text-right">{label}</div>
      <div className="flex-1 h-2 bg-slate-700 rounded-full overflow-hidden">
        <div 
          className={`h-full rounded-full ${color}`} 
          style={{ width: `${pct}%` }}
        ></div>
      </div>
    </div>
  );
};

