import React, { useState } from 'react';
import { CarModel, GameConfig } from '../types';
import { GAME_CONFIG } from '../constants';

interface CarMakerProps {
  onClose: () => void;
}

const CarMaker: React.FC<CarMakerProps> = ({ onClose }) => {
  // Local state for the custom car being built
  const [car, setCar] = useState<CarModel>({
    id: 'custom-' + Date.now(),
    name: 'Custom Rider',
    color: '#ef4444',
    bodyColor: '#ef4444',
    texture: 'plain',
    textureColor2: '#b91c1c',
    wheelColor: '#1f2937',
    speed: 1.0,
    acceleration: 0.02,
    density: 0.004,
    friction: 1.0,
    driveTrain: 'RWD',
    shape: 'coupe',
    imageScale: 1.0,
    imageYOffset: 0
  });

  const handleChange = (key: keyof CarModel, value: any) => {
    setCar(prev => ({ ...prev, [key]: value }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
      const file = e.target.files?.[0];
      if (file) {
          const reader = new FileReader();
          reader.onload = (ev) => {
              if (ev.target?.result) {
                  setCar(prev => ({
                      ...prev,
                      imageUrl: ev.target!.result as string,
                      texture: 'plain', // Reset texture mode to avoid conflicts
                      imageScale: 1.5, // Default nice scale
                      imageYOffset: -10
                  }));
              }
          };
          reader.readAsDataURL(file);
      }
  };

  const handleClearImage = () => {
      setCar(prev => ({ ...prev, imageUrl: undefined }));
  };

  const handleCopy = () => {
    navigator.clipboard.writeText(JSON.stringify(car, null, 2));
    alert("Car JSON copied to clipboard!");
  };

  const handleRandomize = () => {
      const textures = ['plain', 'striped', 'dots', 'checker', 'gradient'];
      const driveTrains = ['RWD', 'FWD', 'AWD'];
      const shapes = ['coupe', 'buggy', 'jeep', 'racer', 'van', 'supercar'];
      const randomColor = () => '#' + Math.floor(Math.random()*16777215).toString(16).padStart(6, '0');

      setCar(prev => ({
          ...prev,
          bodyColor: randomColor(),
          textureColor2: randomColor(),
          wheelColor: '#1f2937', // Keep wheels dark by default usually
          texture: textures[Math.floor(Math.random() * textures.length)] as any,
          driveTrain: driveTrains[Math.floor(Math.random() * driveTrains.length)] as any,
          shape: shapes[Math.floor(Math.random() * shapes.length)] as any,
          imageUrl: undefined // clear image on random
      }));
  };

  return (
    <div className="absolute inset-0 z-50 bg-slate-900 text-white flex flex-col">
       <div className="p-4 border-b border-slate-700 bg-slate-800 flex justify-between items-center">
            <h2 className="text-2xl font-bold">🛠️ Car Maker</h2>
            <div className="flex gap-4">
                 <button onClick={handleRandomize} className="px-4 py-2 bg-purple-600 rounded font-bold hover:bg-purple-500">🎲 Random</button>
                 <button onClick={handleCopy} className="px-4 py-2 bg-blue-600 rounded font-bold hover:bg-blue-500">Copy JSON</button>
                 <button onClick={onClose} className="px-4 py-2 bg-slate-600 rounded font-bold hover:bg-slate-500">Exit</button>
            </div>
       </div>

       <div className="flex-1 flex overflow-hidden">
            {/* Controls */}
            <div className="w-96 bg-slate-800 p-6 overflow-y-auto border-r border-slate-700 space-y-6">

                {/* Text Inputs */}
                <div>
                    <label className="text-xs font-bold text-slate-500 uppercase">Name</label>
                    <input 
                        type="text" 
                        value={car.name} 
                        onChange={(e) => handleChange('name', e.target.value)}
                        className="w-full bg-slate-900 border border-slate-600 rounded p-2 text-white mt-1"
                    />
                </div>

                {/* Custom Image Upload */}
                <div className="p-4 bg-slate-700/50 rounded-lg border border-slate-600">
                    <h3 className="text-sm font-bold text-slate-300 mb-2">Custom Image (PNG)</h3>
                    {!car.imageUrl ? (
                        <input 
                            type="file" 
                            accept="image/*"
                            onChange={handleImageUpload}
                            className="text-xs text-slate-400 file:mr-4 file:py-2 file:px-4 file:rounded-full file:border-0 file:text-xs file:font-semibold file:bg-blue-600 file:text-white hover:file:bg-blue-500 cursor-pointer"
                        />
                    ) : (
                        <div className="space-y-3">
                            <div className="flex items-center justify-between">
                                <span className="text-xs text-green-400">Image Loaded!</span>
                                <button onClick={handleClearImage} className="text-xs text-red-400 hover:text-red-300 underline">Remove</button>
                            </div>
                            <RangeControl label="Size Scale" value={car.imageScale || 1.0} min={0.5} max={3.0} step={0.1} onChange={(v) => handleChange('imageScale', v)} />
                            <RangeControl label="Vertical Offset" value={car.imageYOffset || 0} min={-100} max={100} step={1} onChange={(v) => handleChange('imageYOffset', v)} />
                        </div>
                    )}
                </div>

                {/* Colors - Only show if no image */}
                {!car.imageUrl && (
                    <div className="space-y-4 border-b border-slate-700 pb-4">
                        <h3 className="text-sm font-bold text-slate-400">Body & Style</h3>
                         <div>
                             <label className="text-xs font-bold text-slate-500 uppercase">Shape</label>
                             <select 
                                value={car.shape || 'coupe'}
                                onChange={(e) => handleChange('shape', e.target.value)}
                                className="w-full bg-slate-900 border border-slate-600 rounded p-2 text-white mt-1"
                             >
                                <option value="coupe">Coupe (Standard)</option>
