                                            <rect x="-70" y="-35" width="30" height="15" fill="#1e293b" rx="2" />
                                            <rect x="-30" y="-35" width="30" height="15" fill="#1e293b" rx="2" />
                                        </>
                                    )}

                                    {car.shape === 'supercar' && (
                                        <>
                                            <path
                                                d="M -90 15 L -80 0 L -40 -20 L 20 -20 L 95 5 L 100 15 Z"
                                                fill={car.texture !== 'plain' ? "url(#maker-preview-pattern)" : car.bodyColor}
                                                stroke="rgba(0,0,0,0.5)" strokeWidth="2"
                                            />
                                            <path d="M -30 -20 L -10 -30 L 30 -20 Z" fill="#1e293b" />
                                             <path d="M -80 0 L -90 -15 L -60 -5" fill={car.bodyColor} stroke="rgba(0,0,0,0.5)" />
                                        </>
                                    )}
                                </g>
                            )}

                            {/* Wheels - Always visible on top of body unless hidden, but usually underneath in side view. 
                                Actually for side view, wheels are often on top or cut out. 
                                Let's render wheels on top to be safe for custom images. */}
                            <g transform={`translate(${-GAME_CONFIG.CAR_WIDTH/2.2 + GAME_CONFIG.WHEEL_SIZE}, ${GAME_CONFIG.CAR_HEIGHT/2})`}>
                                <circle r={GAME_CONFIG.WHEEL_SIZE} fill="#1f2937" stroke="black" strokeWidth="2" />
                                <circle r={GAME_CONFIG.WHEEL_SIZE * 0.7} fill={car.wheelColor} stroke="black" strokeWidth="1" />
                                <g stroke="#1f2937" strokeWidth="4" strokeLinecap="round">
                                    <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE * 0.7} x2="0" y2={GAME_CONFIG.WHEEL_SIZE * 0.7} />
                                    <line x1={-GAME_CONFIG.WHEEL_SIZE * 0.6} y1={-GAME_CONFIG.WHEEL_SIZE * 0.35} x2={GAME_CONFIG.WHEEL_SIZE * 0.6} y2={GAME_CONFIG.WHEEL_SIZE * 0.35} />
                                    <line x1={-GAME_CONFIG.WHEEL_SIZE * 0.6} y1={GAME_CONFIG.WHEEL_SIZE * 0.35} x2={GAME_CONFIG.WHEEL_SIZE * 0.6} y2={-GAME_CONFIG.WHEEL_SIZE * 0.35} />
                                </g>
                            </g>

                            <g transform={`translate(${GAME_CONFIG.CAR_WIDTH/2.2 - GAME_CONFIG.WHEEL_SIZE}, ${GAME_CONFIG.CAR_HEIGHT/2})`}>
                                <circle r={GAME_CONFIG.WHEEL_SIZE} fill="#1f2937" stroke="black" strokeWidth="2" />
                                <circle r={GAME_CONFIG.WHEEL_SIZE * 0.7} fill={car.wheelColor} stroke="black" strokeWidth="1" />
                                <g stroke="#1f2937" strokeWidth="4" strokeLinecap="round">
                                    <line x1="0" y1={-GAME_CONFIG.WHEEL_SIZE * 0.7} x2="0" y2={GAME_CONFIG.WHEEL_SIZE * 0.7} />
                                    <line x1={-GAME_CONFIG.WHEEL_SIZE * 0.6} y1={-GAME_CONFIG.WHEEL_SIZE * 0.35} x2={GAME_CONFIG.WHEEL_SIZE * 0.6} y2={GAME_CONFIG.WHEEL_SIZE * 0.35} />
                                    <line x1={-GAME_CONFIG.WHEEL_SIZE * 0.6} y1={GAME_CONFIG.WHEEL_SIZE * 0.35} x2={GAME_CONFIG.WHEEL_SIZE * 0.6} y2={-GAME_CONFIG.WHEEL_SIZE * 0.35} />
                                </g>
                            </g>
                         </g>
                    </svg>
                 </div>

                 <div className="mt-8 text-center text-slate-400 max-w-md">
                    <p className="text-sm">Upload a side-view PNG of a car with a transparent background for best results.</p>
                 </div>
            </div>
       </div>
    </div>
  );
};

const RangeControl: React.FC<{ label: string; value: number; min: number; max: number; step: number; onChange: (v: number) => void }> = ({ label, value, min, max, step, onChange }) => (
    <div>
        <div className="flex justify-between text-sm mb-1 text-slate-300">
            <label>{label}</label>
            <span className="font-mono text-blue-400">{Number(value).toFixed(3)}</span>
        </div>
        <input 
            type="range"
            min={min}
            max={max}
            step={step}
            value={value}
            onChange={(e) => onChange(parseFloat(e.target.value))}
            className="w-full accent-blue-500 h-2 bg-slate-700 rounded-lg appearance-none cursor-pointer"
        />
    </div>
);

export default CarMaker;

export enum GameState {
  MENU = 'MENU',
  PLAYING = 'PLAYING',
  GAME_OVER = 'GAME_OVER',
  MAP_MAKER = 'MAP_MAKER',
  CAR_MAKER = 'CAR_MAKER',
}

export interface GameScore {
  distance: number;
  bestDistance: number;
}

export type CarShape = 'coupe' | 'buggy' | 'jeep' | 'racer' | 'van' | 'supercar' | 'truck' | 'bike';

export interface CarModel {
  id: string;
  name: string;
  color: string; // Main display color (UI)
  bodyColor: string; // Hex for the chassis base
  texture: 'plain' | 'striped' | 'dots' | 'checker' | 'gradient';
  textureColor2: string; // Secondary color for pattern/gradient
  wheelColor: string;
  speed: number; // Max angular velocity
  acceleration: number; // Torque increment
  density: number; // Weight/Stability
  friction: number; // Grip
  driveTrain: 'FWD' | 'RWD' | 'AWD'; // New property for powered wheels
  shape: CarShape; // New property for visual geometry

  // Custom Image Support
  imageUrl?: string;
  imageScale?: number;
  imageYOffset?: number;
}

export interface MapConfig {
  id: string;
  name: string;
  description: string;
  backgroundType: 'earth' | 'moon' | 'highway' | 'mystical';
  skyColorStart: string;
  skyColorEnd: string;
  groundColor: string;
  groundDarkColor: string;
  particleColor: string;
  configOverrides: Partial<GameConfig>;
}

export interface GameConfig {
  CAR_WIDTH: number;
  CAR_HEIGHT: number;
  WHEEL_SIZE: number;
  GRAVITY: number;
  CAR_SPEED: number;
  ACCELERATION: number;
  GROUND_ROTATION_SPEED: number;
  AIR_ROTATION_SPEED: number;
  MAX_ROTATION_SPEED: number;
  CHUNK_SIZE: number;
  RENDER_DISTANCE: number;
  TERRAIN_SEGMENT_WIDTH: number;
  WALL_DISTANCE: number;
  BASE_VIEWPORT_WIDTH: number;
  BASE_VIEWPORT_HEIGHT: number;
  MAX_ZOOM_FACTOR: number;
  COIN_SIZE: number;
  COIN_VALUE: number;

  // Fuel System
  MAX_FUEL: number;
  FUEL_CONSUMPTION: number;
  FUEL_CAN_VALUE: number;
  FUEL_CAN_SIZE: number;

  PARTICLE_POOL_SIZE: number;
  PARTICLE_LIFETIME: number;
  DAY_CYCLE_FRAMES: number;
  LAMP_SPACING: number;

  // Terrain Generation Config
  TERRAIN_NOISE_FREQ_1: number;
  TERRAIN_AMP_1: number;
  TERRAIN_NOISE_FREQ_2: number;
  TERRAIN_AMP_2: number;
  TERRAIN_NOISE_FREQ_3: number;
