  // Local state for the custom car being built
  const [car, setCar] = useState<CarModel>({
    id: 'custom-' + Date.now(),
    name: 'Custom Rider',
    color: '#ef4444',
    bodyColor: '#ef4444',
    texture: 'plain',
    textureColor2: '#b91c1c',
    wheelColor: '#1f2937',
    speed: 1.0,
    acceleration: 0.02,
    density: 0.004,
