import React, { useState, useEffect } from 'react';
import Game from './components/Game';
import MainMenu from './components/MainMenu';
import GameOver from './components/GameOver';
import CarSelection from './components/CarSelection';
import MapSelection from './components/MapSelection';
import MapMaker from './components/MapMaker';
import CarMaker from './components/CarMaker';
import { GameState, CarModel, GameConfig, MapConfig } from './types';
import { CAR_MODELS, GAME_CONFIG, MAPS } from './constants';

const CONFIG_STORAGE_KEY = 'hill_climber_config_v1';

const App: React.FC = () => {
  const [gameState, setGameState] = useState<GameState>(GameState.MENU);
  const [score, setScore] = useState(0); // Distance
  const [coins, setCoins] = useState(0);
  const [bestScore, setBestScore] = useState(0);

  // Game Configuration State (Persisted)
  const [gameConfig, setGameConfig] = useState<GameConfig>(GAME_CONFIG);

  // Selection State
  const [selectedCar, setSelectedCar] = useState<CarModel>(CAR_MODELS[0]);
  const [selectedMap, setSelectedMap] = useState<MapConfig>(MAPS[0]);

  const [isGarageOpen, setIsGarageOpen] = useState(false);
  const [isMapSelectOpen, setIsMapSelectOpen] = useState(false);

  // Load Config on Mount
  useEffect(() => {
    const savedConfig = localStorage.getItem(CONFIG_STORAGE_KEY);
    if (savedConfig) {
        try {
            const parsed = JSON.parse(savedConfig);
            setGameConfig(prev => ({ ...prev, ...parsed }));
        } catch (e) {
            console.error("Failed to load config", e);
        }
    }
  }, []);

  // Save Config on Change
  useEffect(() => {
    localStorage.setItem(CONFIG_STORAGE_KEY, JSON.stringify(gameConfig));
  }, [gameConfig]);

  const updateConfig = (key: keyof GameConfig, value: number) => {
      setGameConfig(prev => ({ ...prev, [key]: value }));
  };

  const resetConfig = () => {
      setGameConfig(GAME_CONFIG);
  };

  const startGame = () => {
    setScore(0);
    setCoins(0);
    setGameState(GameState.PLAYING);
  };

  const handleGameOver = (distance: number, collectedCoins: number) => {
    setScore(distance);
    setCoins(collectedCoins);
    if (distance > bestScore) {
      setBestScore(distance);
    }
    setGameState(GameState.GAME_OVER);
  };

  // Merge Base Config with Map Overrides for the active game session
  const activeConfig = { ...gameConfig, ...selectedMap.configOverrides };

  return (
    <div className="w-screen h-screen overflow-hidden font-sans select-none">
      {gameState === GameState.MENU && (
        <MainMenu 
          onStart={startGame} 
          onOpenGarage={() => setIsGarageOpen(true)}
          onOpenMapSelect={() => setIsMapSelectOpen(true)}
          onOpenMapMaker={() => setGameState(GameState.MAP_MAKER)}
          onOpenCarMaker={() => setGameState(GameState.CAR_MAKER)}
          bestDistance={bestScore} 
        />
      )}

      {gameState === GameState.PLAYING && (
        <Game 
            onGameOver={handleGameOver} 
            selectedCar={selectedCar} 
            selectedMap={selectedMap}
            config={activeConfig}
            onUpdateConfig={updateConfig}
            onResetConfig={resetConfig}
            onExit={() => setGameState(GameState.MENU)}
        />
      )}

      {gameState === GameState.GAME_OVER && (
        <GameOver 
          distance={score} 
          bestDistance={bestScore} 
          onRestart={startGame} 
        />
      )}

      {gameState === GameState.MAP_MAKER && (
          <MapMaker 
             config={activeConfig} 
             onUpdateConfig={updateConfig} 
             onClose={() => setGameState(GameState.MENU)} 
          />
      )}

      {gameState === GameState.CAR_MAKER && (
          <CarMaker onClose={() => setGameState(GameState.MENU)} />
      )}

      {isGarageOpen && (
        <CarSelection 
          currentCarId={selectedCar.id} 
          onSelect={setSelectedCar} 
          onClose={() => setIsGarageOpen(false)} 
        />
      )}

      {isMapSelectOpen && (
        <MapSelection 
          currentMapId={selectedMap.id} 
          onSelect={setSelectedMap} 
          onClose={() => setIsMapSelectOpen(false)} 
        />
      )}

      {/* Background for Menu/GameOver states */}
      {gameState !== GameState.PLAYING && gameState !== GameState.MAP_MAKER && gameState !== GameState.CAR_MAKER && (
        <div className="absolute inset-0 -z-10 bg-gradient-to-b" style={{ 
            backgroundImage: `linear-gradient(to bottom, ${selectedMap.skyColorStart}, ${selectedMap.skyColorEnd})` 
        }}>
           <div className="absolute bottom-0 w-full h-1/3 transform skew-y-3 origin-bottom-right" style={{ backgroundColor: selectedMap.groundDarkColor }}></div>
           <div className="absolute bottom-0 w-full h-1/4 transform -skew-y-2 origin-bottom-left" style={{ backgroundColor: selectedMap.groundColor }}></div>
        </div>
      )}
    </div>
  );
};

export default App;

import { GameConfig, CarModel } from '../types';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp, 4: Fence
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  fuelBodies: any[];
  waterBodies: any[];
  bombBodies: any[];
  islandBodies: any[];
  rampBodies: any[];
  obstacleBodies: any[];
  endY: number;
  endGlobalIndex: number;
  nextSegmentsSinceFuel: number; 
  id: number;
}

export const createEngine = (config: GameConfig) => {
  const engine = Matter.Engine.create();
  engine.gravity.y = config.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number, carConfig: CarModel, gameConfig: GameConfig) => {
  // Use car specific config if available, fallback to global config
  const CAR_WIDTH = carConfig.width || gameConfig.CAR_WIDTH;
  const CAR_HEIGHT = carConfig.height || gameConfig.CAR_HEIGHT;
  const WHEEL_SIZE = carConfig.wheelSize || gameConfig.WHEEL_SIZE;

  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: carConfig.density, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: carConfig.bodyColor },
    chamfer: { radius: 15 } 
  });

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: carConfig.friction,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  const wheelA = Matter.Bodies.circle(x - CAR_WIDTH / 2.2 + WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x + CAR_WIDTH / 2.2 - WHEEL_SIZE, y + CAR_HEIGHT / 2, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  const suspensionStiffness = 0.5; // Increased from 0.3 to reduce wobble
  const suspensionDamping = 0.3;   // Increased from 0.2 for stability
  const suspensionLength = 9;      

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: -CAR_WIDTH / 2 + WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: CAR_WIDTH / 2 - WHEEL_SIZE, y: CAR_HEIGHT / 2 },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

/**
 * Calculates the noise/height for a specific index. 
 * Supports different logic based on map type.
 */
export const getTerrainNoise = (globalIndex: number, config: GameConfig, mapType: string = 'earth'): number => {
    const baseHeight = 70;

    if (mapType === 'mystical') {
        // Mystical Logic: Gently rolling flat cave floor
        const nx = globalIndex * 0.02; 
        const h = Math.sin(nx) * 50; // Very gentle large waves

        const jagged = Math.sin(globalIndex * 0.5) * 10; // Slight roughness

        return (h + jagged) * config.TERRAIN_AMP_1; 
    }

    // Standard Logic
    const nx = globalIndex * config.TERRAIN_NOISE_FREQ_1;
    const nzOsc = Math.sin(nx * 0.2);
    let amp = 0.1;
    if (nzOsc > 0.3) amp = 1.0;
    else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

    const nPrimary = Math.sin(nx) * config.TERRAIN_AMP_1;
    const nSecondary = Math.cos(globalIndex * config.TERRAIN_NOISE_FREQ_2) * config.TERRAIN_AMP_2;
    const nRumble = Math.sin(globalIndex * config.TERRAIN_NOISE_FREQ_3) * config.TERRAIN_AMP_3;

    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001));

    return (nPrimary + nSecondary + nRumble) * amp * difficultyMultiplier * baseHeight;
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean,
    config: GameConfig,
    mapType: string = 'earth',
    startSegmentsSinceFuel: number = 0
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, FUEL_CAN_SIZE, LAMP_SPACING } = config;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];
  const fuelBodies: any[] = [];
  const waterBodies: any[] = [];
  const bombBodies: any[] = [];
  const islandBodies: any[] = [];
  const rampBodies: any[] = [];
  const obstacleBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;
  let lastLampX = startX;
  let coinStreak = 0;
  let segmentsSinceFuel = startSegmentsSinceFuel;

  // Track previous segments to ensure we don't spam hazards
  let segmentsSinceWater = 0;
  let segmentsSinceIsland = 0;
  let segmentsSinceRamp = 0;

  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;
    segmentsSinceFuel++;
    segmentsSinceWater++;
    segmentsSinceIsland++;
    segmentsSinceRamp++;

    const noiseCurrent = getTerrainNoise(globalIndex, config, mapType);
    const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);

    const dy = -(noiseCurrent - noisePrev); 

    currentY = prevY + dy;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Analysis for features ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const isFlatEnough = slopeFactor > 0.85; 
    const isVeryFlat = slopeFactor > 0.95;   

    // --- Mystical Map Features ---
    if (mapType === 'mystical') {
        // 1. Water Pools - Rare, only on flat
        if (Math.random() < 0.1 && isVeryFlat && segmentsSinceWater > 30) {
            const poolWidth = 240;
            const poolHeight = 50;
            const wx = currentX + poolWidth/2;
            const wy = currentY - 15; 

            const water = Matter.Bodies.rectangle(wx, wy, poolWidth, poolHeight, {
                isSensor: true,
                isStatic: true,
                label: 'water',
                render: { visible: false }
            });
            waterBodies.push(water);
            segmentsSinceWater = 0;
        }

        // 2. Hidden Bombs (Mines) - Frequent enough to be dangerous
        if (Math.random() < 0.08 && isFlatEnough) {
             const bx = currentX;
             const by = currentY + 5; 
             const bomb = Matter.Bodies.circle(bx, by, 10, {
                 isSensor: true,
                 isStatic: true,
                 label: 'bomb',
                 render: { visible: false }
             });
             bombBodies.push(bomb);
        }

        // 3. MASSIVE FLOATING ISLANDS
        if (Math.random() < 0.15 && segmentsSinceIsland > 40) {
            const width = 600 + Math.random() * 800; // Huge islands
            const ix = currentX + width / 2;
            const iy = currentY - 350 - (Math.random() * 150); // High ceiling

            const vertices = [];
            const steps = 10;
            const stepW = width / steps;

            for(let j=0; j<=steps; j++) {
                vertices.push({ x: -width/2 + j*stepW, y: (Math.random() * 10) - 5 });
            }
            for(let j=steps; j>=0; j--) {
                const jaggedY = 60 + Math.random() * 80; 
                vertices.push({ x: -width/2 + j*stepW, y: jaggedY });
            }

            const island = Matter.Bodies.fromVertices(ix, iy, [vertices], {
                isStatic: true,
                friction: 1.0,
                label: 'ground', 
                render: { visible: false },
                chamfer: { radius: 5 }
            });

            if (island) {
                islandBodies.push(island);
                segmentsSinceIsland = 0;

                // Chance to spawn obstacles on top of island
                if (Math.random() < 0.3) {
                     const box = Matter.Bodies.rectangle(ix, iy - 50, 60, 60, {
                        isStatic: false,
                        density: 0.005,
                        friction: 0.8,
                        label: 'obstacle',
                        render: { visible: false }
                     });
                     obstacleBodies.push(box);
                } else if (Math.random() < 0.5) {
                    const coin = Matter.Bodies.circle(ix, iy - 60, COIN_SIZE, {
                        isSensor: true,
                        isStatic: true,
                        label: 'coin',
                        render: { visible: false }
                    });
                    coinBodies.push(coin);
                }
            }
        }

        // 4. JUMP RAMPS (Significantly Reduced Frequency & Varied)
        // Reduced probability from 0.15 to 0.06 and increased spacing check
        if (Math.random() < 0.06 && isFlatEnough && segmentsSinceIsland > 5 && segmentsSinceWater > 5 && segmentsSinceRamp > 25) {

            const rampType = Math.random(); // 0-0.5 Standard Wedge, 0.5-1.0 Steep Kicker
            let rampWidth, rampHeight, vertices;

            if (rampType < 0.5) {
                // Standard Wedge
                rampWidth = 300 + Math.random() * 100;
                rampHeight = 100 + Math.random() * 40;
                vertices = [
                    { x: 0, y: rampHeight },        
                    { x: rampWidth, y: rampHeight }, 
                    { x: rampWidth, y: 0 }           
                ];
            } else {
                // Steep Kicker (Shorter length, same height)
                rampWidth = 150 + Math.random() * 50;
                rampHeight = 120 + Math.random() * 30;
                vertices = [
                    { x: 0, y: rampHeight },        
                    { x: rampWidth, y: rampHeight }, 
                    { x: rampWidth, y: -20 } // slight lip curve approximation
                ];
            }

            const rampX = currentX + rampWidth / 2;
            const rampY = currentY - rampHeight / 2;

            const ramp = Matter.Bodies.fromVertices(rampX, rampY, [vertices], {
                isStatic: true,
                friction: 1.0,
                label: 'ground',
                render: { visible: false }
            });

            if (ramp) {
                const bounds = ramp.bounds;
                const bottomY = bounds.max.y;
                const diff = currentY - bottomY;
                Matter.Body.setPosition(ramp, { x: ramp.position.x, y: ramp.position.y + diff + 5 }); 

                rampBodies.push(ramp);
                segmentsSinceRamp = 0;
            }
        }

        // 5. MYSTICAL OBSTACLES (Movable Boxes)
        if (Math.random() < 0.08 && isFlatEnough && segmentsSinceRamp > 5) {
            const size = 50 + Math.random() * 30;
            const ox = currentX;
            const oy = currentY - size; // Drop from slightly above

            const box = Matter.Bodies.rectangle(ox, oy, size, size, {
                isStatic: false, // MOVABLE!
                density: 0.002,  // Light enough to push
                friction: 0.5,
                restitution: 0.1,
                label: 'obstacle',
                render: { visible: false }
            });
            obstacleBodies.push(box);
        }
    }

    // --- Decorations ---
    // 1. Grass (Earth Only)
    if (mapType === 'earth') {
        const density = 0.4 * slopeFactor; 
        if (Math.random() < density) {
            const t = Math.random();
            const decoX = prevX + (currentX - prevX) * t;
            const decoY = prevY + (currentY - prevY) * t;

            decorations.push({
                x: decoX,
                y: decoY,
                angle: angle,
                scale: 0.5 + Math.random() * 0.5,
                type: Math.floor(Math.random() * 3) 
            });
        }
    }

    // 2. Lamps
    const lampChance = isNight || mapType === 'highway';
    if (lampChance && (currentX - lastLampX) > LAMP_SPACING) {
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3
        });
        lastLampX = currentX;
    }

    // 3. Fences (Highway)
    if (mapType === 'highway') {
        decorations.push({
            x: prevX,
            y: prevY,
            angle: angle,
            scale: 1.0,
            type: 4
        });
    }

    // --- Collectibles (Fuel & Coins) ---
    const forceFuel = segmentsSinceFuel >= 125; 
    const canSpawnFuel = (segmentsSinceFuel > 80 && isFlatEnough) || forceFuel;

    let fuelSpawnedHere = false;

    if (canSpawnFuel) {
        if (forceFuel || Math.random() < 0.1) {
             const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;

            const fuel = Matter.Bodies.rectangle(cx, cy, FUEL_CAN_SIZE * 0.8, FUEL_CAN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'fuel',
                angle: 0,
                render: { visible: false }
            });
            fuelBodies.push(fuel);
            segmentsSinceFuel = 0;
            coinStreak = 0; 
            fuelSpawnedHere = true;
        }
    }

    if (!fuelSpawnedHere) {
        let placeCoin = false;
        if (coinStreak > 0) {
            if (isFlatEnough) {
                placeCoin = true;
                coinStreak--;
            } else {
                coinStreak = 0;
            }
        } else {
            if (Math.random() < 0.05 && isFlatEnough) {
                coinStreak = 3 + Math.floor(Math.random() * 6);
                placeCoin = true;
                coinStreak--;
            }
        }

        if (placeCoin) {
            const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Ground
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: config.FRICTION || 1.0, 
         frictionStatic: config.FRICTION || 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies, ...fuelBodies, ...waterBodies, ...bombBodies, ...islandBodies, ...rampBodies, ...obstacleBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      fuelBodies,
      waterBodies,
      bombBodies,
      islandBodies,
      rampBodies,
      obstacleBodies,
      endY: currentY,
      endGlobalIndex: globalIndex,
      nextSegmentsSinceFuel: segmentsSinceFuel, 
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import { GameConfig, CarModel } from '../types';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp, 4: Fence
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  fuelBodies: any[];
  waterBodies: any[];
  bombBodies: any[];
  islandBodies: any[];
  rampBodies: any[];
  obstacleBodies: any[];
  endY: number;
  endGlobalIndex: number;
  nextSegmentsSinceFuel: number; 
  id: number;
}

export const createEngine = (config: GameConfig) => {
  const engine = Matter.Engine.create();
  engine.gravity.y = config.GRAVITY;

  engine.positionIterations = 8;
  engine.velocityIterations = 8;

  return engine;
};

export const createCar = (x: number, y: number, carConfig: CarModel, gameConfig: GameConfig) => {
  // Use car specific config if available, fallback to global config
  const CAR_WIDTH = carConfig.width || gameConfig.CAR_WIDTH;
  const CAR_HEIGHT = carConfig.height || gameConfig.CAR_HEIGHT;
  const WHEEL_SIZE = carConfig.wheelSize || gameConfig.WHEEL_SIZE;

  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: carConfig.density, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: carConfig.bodyColor },
    chamfer: { radius: 15 } 
  });

  // Calculate offsets for vertical alignment
  const wheelOffsetX = -CAR_WIDTH / 2 + WHEEL_SIZE;
  const wheelOffsetY = CAR_HEIGHT / 2;

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: carConfig.friction,       
    frictionStatic: 1.5, 
    density: 0.02,       
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  // Align wheels vertically with suspension points to prevent horizontal swing at rest
  const wheelA = Matter.Bodies.circle(x + wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x - wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  // Increased stiffness to prevent side-to-side wobble (pendulum effect)
  const suspensionStiffness = 0.8; 
  const suspensionDamping = 0.4;   
  const suspensionLength = 10;      

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: -wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

/**
 * Calculates the noise/height for a specific index. 
 * Supports different logic based on map type.
 */
export const getTerrainNoise = (globalIndex: number, config: GameConfig, mapType: string = 'earth'): number => {
    const baseHeight = 70;

    if (mapType === 'mystical') {
        // Mystical Logic: Gently rolling flat cave floor
        const nx = globalIndex * 0.02; 
        const h = Math.sin(nx) * 50; // Very gentle large waves

        const jagged = Math.sin(globalIndex * 0.5) * 10; // Slight roughness

        return (h + jagged) * config.TERRAIN_AMP_1; 
    }

    // Standard Logic
    const nx = globalIndex * config.TERRAIN_NOISE_FREQ_1;
    const nzOsc = Math.sin(nx * 0.2);
    let amp = 0.1;
    if (nzOsc > 0.3) amp = 1.0;
    else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

    const nPrimary = Math.sin(nx) * config.TERRAIN_AMP_1;
    const nSecondary = Math.cos(globalIndex * config.TERRAIN_NOISE_FREQ_2) * config.TERRAIN_AMP_2;
    const nRumble = Math.sin(globalIndex * config.TERRAIN_NOISE_FREQ_3) * config.TERRAIN_AMP_3;

    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001));

    return (nPrimary + nSecondary + nRumble) * amp * difficultyMultiplier * baseHeight;
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean,
    config: GameConfig,
    mapType: string = 'earth',
    startSegmentsSinceFuel: number = 0
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, FUEL_CAN_SIZE, LAMP_SPACING } = config;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];
  const fuelBodies: any[] = [];
  const waterBodies: any[] = [];
  const bombBodies: any[] = [];
  const islandBodies: any[] = [];
  const rampBodies: any[] = [];
  const obstacleBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;
  let lastLampX = startX;
  let coinStreak = 0;
  let segmentsSinceFuel = startSegmentsSinceFuel;

  // Track previous segments to ensure we don't spam hazards
  let segmentsSinceWater = 0;
  let segmentsSinceIsland = 0;
  let segmentsSinceRamp = 0;

  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;
    segmentsSinceFuel++;
    segmentsSinceWater++;
    segmentsSinceIsland++;
    segmentsSinceRamp++;

    const noiseCurrent = getTerrainNoise(globalIndex, config, mapType);
    const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);

    const dy = -(noiseCurrent - noisePrev); 

    currentY = prevY + dy;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Analysis for features ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const isFlatEnough = slopeFactor > 0.85; 
    const isVeryFlat = slopeFactor > 0.95;   

    // --- Mystical Map Features ---
    if (mapType === 'mystical') {
        // 1. Water Pools - Rare, only on flat
        if (Math.random() < 0.1 && isVeryFlat && segmentsSinceWater > 30) {
            const poolWidth = 240;
            const poolHeight = 50;
            const wx = currentX + poolWidth/2;
            const wy = currentY - 15; 

            const water = Matter.Bodies.rectangle(wx, wy, poolWidth, poolHeight, {
                isSensor: true,
                isStatic: true,
                label: 'water',
                render: { visible: false }
            });
            waterBodies.push(water);
            segmentsSinceWater = 0;
        }

        // 2. Hidden Bombs (Mines) - Frequent enough to be dangerous
        if (Math.random() < 0.08 && isFlatEnough) {
             const bx = currentX;
             const by = currentY + 5; 
             const bomb = Matter.Bodies.circle(bx, by, 10, {
                 isSensor: true,
                 isStatic: true,
                 label: 'bomb',
                 render: { visible: false }
             });
             bombBodies.push(bomb);
        }

        // 3. MASSIVE FLOATING ISLANDS
        if (Math.random() < 0.15 && segmentsSinceIsland > 40) {
            const width = 600 + Math.random() * 800; // Huge islands
            const ix = currentX + width / 2;
            const iy = currentY - 350 - (Math.random() * 150); // High ceiling

            const vertices = [];
            const steps = 10;
            const stepW = width / steps;

            for(let j=0; j<=steps; j++) {
                vertices.push({ x: -width/2 + j*stepW, y: (Math.random() * 10) - 5 });
            }
            for(let j=steps; j>=0; j--) {
                const jaggedY = 60 + Math.random() * 80; 
                vertices.push({ x: -width/2 + j*stepW, y: jaggedY });
            }

            const island = Matter.Bodies.fromVertices(ix, iy, [vertices], {
                isStatic: true,
                friction: 1.0,
                label: 'ground', 
                render: { visible: false },
                chamfer: { radius: 5 }
            });

            if (island) {
                islandBodies.push(island);
                segmentsSinceIsland = 0;

                // Chance to spawn obstacles on top of island
                if (Math.random() < 0.3) {
                     const box = Matter.Bodies.rectangle(ix, iy - 50, 60, 60, {
                        isStatic: false,
                        density: 0.005,
                        friction: 0.8,
                        label: 'obstacle',
                        render: { visible: false }
                     });
                     obstacleBodies.push(box);
                } else if (Math.random() < 0.5) {
                    const coin = Matter.Bodies.circle(ix, iy - 60, COIN_SIZE, {
                        isSensor: true,
                        isStatic: true,
                        label: 'coin',
                        render: { visible: false }
                    });
                    coinBodies.push(coin);
                }
            }
        }

        // 4. JUMP RAMPS (Significantly Reduced Frequency & Varied)
        // Reduced probability from 0.15 to 0.06 and increased spacing check
        if (Math.random() < 0.06 && isFlatEnough && segmentsSinceIsland > 5 && segmentsSinceWater > 5 && segmentsSinceRamp > 25) {

            const rampType = Math.random(); // 0-0.5 Standard Wedge, 0.5-1.0 Steep Kicker
            let rampWidth, rampHeight, vertices;

            if (rampType < 0.5) {
                // Standard Wedge
                rampWidth = 300 + Math.random() * 100;
                rampHeight = 100 + Math.random() * 40;
                vertices = [
                    { x: 0, y: rampHeight },        
                    { x: rampWidth, y: rampHeight }, 
                    { x: rampWidth, y: 0 }           
                ];
            } else {
                // Steep Kicker (Shorter length, same height)
                rampWidth = 150 + Math.random() * 50;
                rampHeight = 120 + Math.random() * 30;
                vertices = [
                    { x: 0, y: rampHeight },        
                    { x: rampWidth, y: rampHeight }, 
                    { x: rampWidth, y: -20 } // slight lip curve approximation
                ];
            }

            const rampX = currentX + rampWidth / 2;
            const rampY = currentY - rampHeight / 2;

            const ramp = Matter.Bodies.fromVertices(rampX, rampY, [vertices], {
                isStatic: true,
                friction: 1.0,
                label: 'ground',
                render: { visible: false }
            });

            if (ramp) {
                const bounds = ramp.bounds;
                const bottomY = bounds.max.y;
                const diff = currentY - bottomY;
                Matter.Body.setPosition(ramp, { x: ramp.position.x, y: ramp.position.y + diff + 5 }); 

                rampBodies.push(ramp);
                segmentsSinceRamp = 0;
            }
        }

        // 5. MYSTICAL OBSTACLES (Movable Boxes)
        if (Math.random() < 0.08 && isFlatEnough && segmentsSinceRamp > 5) {
            const size = 50 + Math.random() * 30;
            const ox = currentX;
            const oy = currentY - size; // Drop from slightly above

            const box = Matter.Bodies.rectangle(ox, oy, size, size, {
                isStatic: false, // MOVABLE!
                density: 0.002,  // Light enough to push
                friction: 0.5,
                restitution: 0.1,
                label: 'obstacle',
                render: { visible: false }
            });
            obstacleBodies.push(box);
        }
    }

    // --- Decorations ---
    // 1. Grass (Earth Only)
    if (mapType === 'earth') {
        const density = 0.4 * slopeFactor; 
        if (Math.random() < density) {
            const t = Math.random();
            const decoX = prevX + (currentX - prevX) * t;
            const decoY = prevY + (currentY - prevY) * t;

            decorations.push({
                x: decoX,
                y: decoY,
                angle: angle,
                scale: 0.5 + Math.random() * 0.5,
                type: Math.floor(Math.random() * 3) 
            });
        }
    }

    // 2. Lamps
    const lampChance = isNight || mapType === 'highway';
    if (lampChance && (currentX - lastLampX) > LAMP_SPACING) {
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3
        });
        lastLampX = currentX;
    }

    // 3. Fences (Highway)
    if (mapType === 'highway') {
        decorations.push({
            x: prevX,
            y: prevY,
            angle: angle,
            scale: 1.0,
            type: 4
        });
    }

    // --- Collectibles (Fuel & Coins) ---
    const forceFuel = segmentsSinceFuel >= 125; 
    const canSpawnFuel = (segmentsSinceFuel > 80 && isFlatEnough) || forceFuel;

    let fuelSpawnedHere = false;

    if (canSpawnFuel) {
        if (forceFuel || Math.random() < 0.1) {
             const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;

            const fuel = Matter.Bodies.rectangle(cx, cy, FUEL_CAN_SIZE * 0.8, FUEL_CAN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'fuel',
                angle: 0,
                render: { visible: false }
            });
            fuelBodies.push(fuel);
            segmentsSinceFuel = 0;
            coinStreak = 0; 
            fuelSpawnedHere = true;
        }
    }

    if (!fuelSpawnedHere) {
        let placeCoin = false;
        if (coinStreak > 0) {
            if (isFlatEnough) {
                placeCoin = true;
                coinStreak--;
            } else {
                coinStreak = 0;
            }
        } else {
            if (Math.random() < 0.05 && isFlatEnough) {
                coinStreak = 3 + Math.floor(Math.random() * 6);
                placeCoin = true;
                coinStreak--;
            }
        }

        if (placeCoin) {
            const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Ground
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: config.FRICTION || 1.0, 
         frictionStatic: config.FRICTION || 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies, ...fuelBodies, ...waterBodies, ...bombBodies, ...islandBodies, ...rampBodies, ...obstacleBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      fuelBodies,
      waterBodies,
      bombBodies,
      islandBodies,
      rampBodies,
      obstacleBodies,
      endY: currentY,
      endGlobalIndex: globalIndex,
      nextSegmentsSinceFuel: segmentsSinceFuel, 
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};

import { GameConfig, CarModel } from '../types';

// We assume Matter is loaded via CDN globally
const Matter = (window as any).Matter;

export interface Decoration {
  x: number;
  y: number;
  angle: number;
  scale: number;
  type: number; // 0-2: Grass, 3: Lamp, 4: Fence
}

export interface Cloud {
  x: number;
  y: number;
  scale: number;
  speedFactor: number; 
  textureId: number;
}

export interface TerrainChunk {
  composite: any;
  pathData: {x: number, y: number}[];
  decorations: Decoration[];
  coinBodies: any[];
  fuelBodies: any[];
  waterBodies: any[];
  bombBodies: any[];
  islandBodies: any[];
  rampBodies: any[];
  obstacleBodies: any[];
  endY: number;
  endGlobalIndex: number;
  nextSegmentsSinceFuel: number; 
  id: number;
}

export const createEngine = (config: GameConfig) => {
  const engine = Matter.Engine.create();
  engine.gravity.y = config.GRAVITY;

  // High iterations for rigid constraints
  engine.positionIterations = 10;
  engine.velocityIterations = 10;

  return engine;
};

export const createCar = (x: number, y: number, carConfig: CarModel, gameConfig: GameConfig) => {
  // Use car specific config if available, fallback to global config
  const CAR_WIDTH = carConfig.width || gameConfig.CAR_WIDTH;
  const CAR_HEIGHT = carConfig.height || gameConfig.CAR_HEIGHT;
  const WHEEL_SIZE = carConfig.wheelSize || gameConfig.WHEEL_SIZE;

  const group = Matter.Body.nextGroup(true);

  // 1. Chassis
  const chassis = Matter.Bodies.rectangle(x, y, CAR_WIDTH, CAR_HEIGHT, {
    collisionFilter: { group: group },
    density: carConfig.density, 
    friction: 0.3,
    label: 'chassis',
    render: { fillStyle: carConfig.bodyColor },
    chamfer: { radius: 15 } 
  });

  // Calculate offsets for vertical alignment
  // Positions the wheel anchor point near the edge of the chassis
  const wheelOffsetX = -CAR_WIDTH / 2 + WHEEL_SIZE;
  const wheelOffsetY = CAR_HEIGHT / 2;

  // 2. Wheels
  const wheelOptions = {
    collisionFilter: { group: group },
    friction: carConfig.friction,       
    frictionStatic: 1.5, 
    density: 0.01,  // Reduced density to minimize wheel inertia/swing     
    restitution: 0.2,    
    render: { fillStyle: 'black' }
  };

  // Align wheels vertically with suspension points to prevent horizontal swing at rest
  const wheelA = Matter.Bodies.circle(x + wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelBack'
  });

  const wheelB = Matter.Bodies.circle(x - wheelOffsetX, y + wheelOffsetY, WHEEL_SIZE, {
    ...wheelOptions,
    label: 'wheelFront'
  });

  // 3. Suspension
  // Ultra-rigid settings to prevent side-to-side (pendulum) movement
  const suspensionStiffness = 1.0; 
  const suspensionDamping = 0.6;   
  const suspensionLength = 7; // Shortened slightly for tighter control

  const axelA = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelA,
    pointA: { x: wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  const axelB = Matter.Constraint.create({
    bodyA: chassis,
    bodyB: wheelB,
    pointA: { x: -wheelOffsetX, y: wheelOffsetY },
    pointB: { x: 0, y: 0 },
    stiffness: suspensionStiffness,
    damping: suspensionDamping,
    length: suspensionLength,
    render: { visible: false }
  });

  return Matter.Composite.create({
    bodies: [chassis, wheelA, wheelB],
    constraints: [axelA, axelB],
    label: 'car'
  });
};

export const createWall = (x: number) => {
    return Matter.Bodies.rectangle(x, -1000, 100, 5000, {
        isStatic: true,
        label: 'wall',
        render: { visible: false }
    });
};

/**
 * Calculates the noise/height for a specific index. 
 * Supports different logic based on map type.
 */
export const getTerrainNoise = (globalIndex: number, config: GameConfig, mapType: string = 'earth'): number => {
    const baseHeight = 70;

    if (mapType === 'mystical') {
        // Mystical Logic: Gently rolling flat cave floor
        const nx = globalIndex * 0.02; 
        const h = Math.sin(nx) * 50; // Very gentle large waves

        const jagged = Math.sin(globalIndex * 0.5) * 10; // Slight roughness

        return (h + jagged) * config.TERRAIN_AMP_1; 
    }

    // Standard Logic
    const nx = globalIndex * config.TERRAIN_NOISE_FREQ_1;
    const nzOsc = Math.sin(nx * 0.2);
    let amp = 0.1;
    if (nzOsc > 0.3) amp = 1.0;
    else if (nzOsc >= -0.3) amp = 0.1 + ((nzOsc+0.3)/0.6)*0.9;

    const nPrimary = Math.sin(nx) * config.TERRAIN_AMP_1;
    const nSecondary = Math.cos(globalIndex * config.TERRAIN_NOISE_FREQ_2) * config.TERRAIN_AMP_2;
    const nRumble = Math.sin(globalIndex * config.TERRAIN_NOISE_FREQ_3) * config.TERRAIN_AMP_3;

    const difficultyMultiplier = Math.min(2.5, 1 + (globalIndex * 0.001));

    return (nPrimary + nSecondary + nRumble) * amp * difficultyMultiplier * baseHeight;
};

export const generateTerrainChunk = (
    chunkId: number,
    startX: number, 
    startY: number, 
    startGlobalIndex: number, 
    length: number,
    isNight: boolean,
    config: GameConfig,
    mapType: string = 'earth',
    startSegmentsSinceFuel: number = 0
): TerrainChunk => {
  const { TERRAIN_SEGMENT_WIDTH, COIN_SIZE, FUEL_CAN_SIZE, LAMP_SPACING } = config;
  const segments = Math.floor(length / TERRAIN_SEGMENT_WIDTH);

  const groundDepth = 800; 
  const pathPoints = []; 
  const decorations: Decoration[] = [];
  const coinBodies: any[] = [];
  const fuelBodies: any[] = [];
  const waterBodies: any[] = [];
  const bombBodies: any[] = [];
  const islandBodies: any[] = [];
  const rampBodies: any[] = [];
  const obstacleBodies: any[] = [];

  pathPoints.push({ x: startX, y: startY });       

  let currentX = startX;
  let currentY = startY;
  let globalIndex = startGlobalIndex;
  let lastLampX = startX;
  let coinStreak = 0;
  let segmentsSinceFuel = startSegmentsSinceFuel;

  // Track previous segments to ensure we don't spam hazards
  let segmentsSinceWater = 0;
  let segmentsSinceIsland = 0;
  let segmentsSinceRamp = 0;

  for (let i = 0; i < segments; i++) {
    const segmentWidth = TERRAIN_SEGMENT_WIDTH;
    const prevX = currentX;
    const prevY = currentY;

    currentX += segmentWidth;
    globalIndex++;
    segmentsSinceFuel++;
    segmentsSinceWater++;
    segmentsSinceIsland++;
    segmentsSinceRamp++;

    const noiseCurrent = getTerrainNoise(globalIndex, config, mapType);
    const noisePrev = getTerrainNoise(globalIndex - 1, config, mapType);

    const dy = -(noiseCurrent - noisePrev); 

    currentY = prevY + dy;

    pathPoints.push({ x: currentX, y: currentY });

    // --- Analysis for features ---
    const angle = Math.atan2(currentY - prevY, currentX - prevX);
    const slopeFactor = 1 - Math.min(Math.abs(Math.sin(angle)), 0.8);
    const isFlatEnough = slopeFactor > 0.85; 
    const isVeryFlat = slopeFactor > 0.95;   

    // --- Mystical Map Features ---
    if (mapType === 'mystical') {
        // 1. Water Pools - Rare, only on flat
        if (Math.random() < 0.1 && isVeryFlat && segmentsSinceWater > 30) {
            const poolWidth = 240;
            const poolHeight = 50;
            const wx = currentX + poolWidth/2;
            const wy = currentY - 15; 

            const water = Matter.Bodies.rectangle(wx, wy, poolWidth, poolHeight, {
                isSensor: true,
                isStatic: true,
                label: 'water',
                render: { visible: false }
            });
            waterBodies.push(water);
            segmentsSinceWater = 0;
        }

        // 2. Hidden Bombs (Mines) - Frequent enough to be dangerous
        if (Math.random() < 0.08 && isFlatEnough) {
             const bx = currentX;
             const by = currentY + 5; 
             const bomb = Matter.Bodies.circle(bx, by, 10, {
                 isSensor: true,
                 isStatic: true,
                 label: 'bomb',
                 render: { visible: false }
             });
             bombBodies.push(bomb);
        }

        // 3. MASSIVE FLOATING ISLANDS
        if (Math.random() < 0.15 && segmentsSinceIsland > 40) {
            const width = 600 + Math.random() * 800; // Huge islands
            const ix = currentX + width / 2;
            const iy = currentY - 350 - (Math.random() * 150); // High ceiling

            const vertices = [];
            const steps = 10;
            const stepW = width / steps;

            for(let j=0; j<=steps; j++) {
                vertices.push({ x: -width/2 + j*stepW, y: (Math.random() * 10) - 5 });
            }
            for(let j=steps; j>=0; j--) {
                const jaggedY = 60 + Math.random() * 80; 
                vertices.push({ x: -width/2 + j*stepW, y: jaggedY });
            }

            const island = Matter.Bodies.fromVertices(ix, iy, [vertices], {
                isStatic: true,
                friction: 1.0,
                label: 'ground', 
                render: { visible: false },
                chamfer: { radius: 5 }
            });

            if (island) {
                islandBodies.push(island);
                segmentsSinceIsland = 0;

                // Chance to spawn obstacles on top of island
                if (Math.random() < 0.3) {
                     const box = Matter.Bodies.rectangle(ix, iy - 50, 60, 60, {
                        isStatic: false,
                        density: 0.005,
                        friction: 0.8,
                        label: 'obstacle',
                        render: { visible: false }
                     });
                     obstacleBodies.push(box);
                } else if (Math.random() < 0.5) {
                    const coin = Matter.Bodies.circle(ix, iy - 60, COIN_SIZE, {
                        isSensor: true,
                        isStatic: true,
                        label: 'coin',
                        render: { visible: false }
                    });
                    coinBodies.push(coin);
                }
            }
        }

        // 4. JUMP RAMPS (Significantly Reduced Frequency & Varied)
        // Reduced probability from 0.15 to 0.06 and increased spacing check
        if (Math.random() < 0.06 && isFlatEnough && segmentsSinceIsland > 5 && segmentsSinceWater > 5 && segmentsSinceRamp > 25) {

            const rampType = Math.random(); // 0-0.5 Standard Wedge, 0.5-1.0 Steep Kicker
            let rampWidth, rampHeight, vertices;

            if (rampType < 0.5) {
                // Standard Wedge
                rampWidth = 300 + Math.random() * 100;
                rampHeight = 100 + Math.random() * 40;
                vertices = [
                    { x: 0, y: rampHeight },        
                    { x: rampWidth, y: rampHeight }, 
                    { x: rampWidth, y: 0 }           
                ];
            } else {
                // Steep Kicker (Shorter length, same height)
                rampWidth = 150 + Math.random() * 50;
                rampHeight = 120 + Math.random() * 30;
                vertices = [
                    { x: 0, y: rampHeight },        
                    { x: rampWidth, y: rampHeight }, 
                    { x: rampWidth, y: -20 } // slight lip curve approximation
                ];
            }

            const rampX = currentX + rampWidth / 2;
            const rampY = currentY - rampHeight / 2;

            const ramp = Matter.Bodies.fromVertices(rampX, rampY, [vertices], {
                isStatic: true,
                friction: 1.0,
                label: 'ground',
                render: { visible: false }
            });

            if (ramp) {
                const bounds = ramp.bounds;
                const bottomY = bounds.max.y;
                const diff = currentY - bottomY;
                Matter.Body.setPosition(ramp, { x: ramp.position.x, y: ramp.position.y + diff + 5 }); 

                rampBodies.push(ramp);
                segmentsSinceRamp = 0;
            }
        }

        // 5. MYSTICAL OBSTACLES (Movable Boxes)
        if (Math.random() < 0.08 && isFlatEnough && segmentsSinceRamp > 5) {
            const size = 50 + Math.random() * 30;
            const ox = currentX;
            const oy = currentY - size; // Drop from slightly above

            const box = Matter.Bodies.rectangle(ox, oy, size, size, {
                isStatic: false, // MOVABLE!
                density: 0.002,  // Light enough to push
                friction: 0.5,
                restitution: 0.1,
                label: 'obstacle',
                render: { visible: false }
            });
            obstacleBodies.push(box);
        }
    }

    // --- Decorations ---
    // 1. Grass (Earth Only)
    if (mapType === 'earth') {
        const density = 0.4 * slopeFactor; 
        if (Math.random() < density) {
            const t = Math.random();
            const decoX = prevX + (currentX - prevX) * t;
            const decoY = prevY + (currentY - prevY) * t;

            decorations.push({
                x: decoX,
                y: decoY,
                angle: angle,
                scale: 0.5 + Math.random() * 0.5,
                type: Math.floor(Math.random() * 3) 
            });
        }
    }

    // 2. Lamps
    const lampChance = isNight || mapType === 'highway';
    if (lampChance && (currentX - lastLampX) > LAMP_SPACING) {
        decorations.push({
            x: currentX,
            y: currentY,
            angle: angle,
            scale: 1.0,
            type: 3
        });
        lastLampX = currentX;
    }

    // 3. Fences (Highway)
    if (mapType === 'highway') {
        decorations.push({
            x: prevX,
            y: prevY,
            angle: angle,
            scale: 1.0,
            type: 4
        });
    }

    // --- Collectibles (Fuel & Coins) ---
    const forceFuel = segmentsSinceFuel >= 125; 
    const canSpawnFuel = (segmentsSinceFuel > 80 && isFlatEnough) || forceFuel;

    let fuelSpawnedHere = false;

    if (canSpawnFuel) {
        if (forceFuel || Math.random() < 0.1) {
             const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;

            const fuel = Matter.Bodies.rectangle(cx, cy, FUEL_CAN_SIZE * 0.8, FUEL_CAN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'fuel',
                angle: 0,
                render: { visible: false }
            });
            fuelBodies.push(fuel);
            segmentsSinceFuel = 0;
            coinStreak = 0; 
            fuelSpawnedHere = true;
        }
    }

    if (!fuelSpawnedHere) {
        let placeCoin = false;
        if (coinStreak > 0) {
            if (isFlatEnough) {
                placeCoin = true;
                coinStreak--;
            } else {
                coinStreak = 0;
            }
        } else {
            if (Math.random() < 0.05 && isFlatEnough) {
                coinStreak = 3 + Math.floor(Math.random() * 6);
                placeCoin = true;
                coinStreak--;
            }
        }

        if (placeCoin) {
            const cx = prevX + (currentX - prevX) * 0.5;
            const cy = prevY + (currentY - prevY) * 0.5 - 50;
            const coin = Matter.Bodies.circle(cx, cy, COIN_SIZE, {
                isSensor: true,
                isStatic: true,
                label: 'coin',
                render: { visible: false }
            });
            coinBodies.push(coin);
        }
    }
  }

  // Create Physics Ground
  const groundParts = [];
  for (let i = 0; i < pathPoints.length - 1; i++) {
     const p1 = pathPoints[i];
     const p2 = pathPoints[i+1];
     const vertices = [
         { x: p1.x, y: p1.y },
         { x: p2.x, y: p2.y },
         { x: p2.x, y: p2.y + groundDepth },
         { x: p1.x, y: p1.y + groundDepth }
     ];
     const center = Matter.Vertices.centre(vertices);
     const body = Matter.Bodies.fromVertices(center.x, center.y, [vertices], {
         isStatic: true,
         friction: config.FRICTION || 1.0, 
         frictionStatic: config.FRICTION || 1.0,
         label: 'ground',
     });
     if (body) groundParts.push(body);
  }

  return { 
      composite: Matter.Composite.create({ bodies: [...groundParts, ...coinBodies, ...fuelBodies, ...waterBodies, ...bombBodies, ...islandBodies, ...rampBodies, ...obstacleBodies] }), 
      pathData: pathPoints,
      decorations,
      coinBodies,
      fuelBodies,
      waterBodies,
      bombBodies,
      islandBodies,
      rampBodies,
      obstacleBodies,
      endY: currentY,
      endGlobalIndex: globalIndex,
      nextSegmentsSinceFuel: segmentsSinceFuel, 
      id: chunkId
  };
};

export const generateClouds = (startX: number, length: number): Cloud[] => {
    const clouds: Cloud[] = [];
    const numClouds = Math.floor(length / 400); 

    for (let i = 0; i < numClouds; i++) {
        const x = startX + (Math.random() * length);
        const y = (Math.random() * 500) - 600; 

        clouds.push({
            x,
            y,
            scale: 0.8 + Math.random() * 1.5,
            speedFactor: 0.05 + Math.random() * 0.2, 
            textureId: Math.floor(Math.random() * 3)
        });
    }
    return clouds;
};
